import{_ as t,o as a,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"78. Higher Duties Allowance","description":"","frontmatter":{"title":"78. Higher Duties Allowance","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","allowances","staffing"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/78-higher-duties-allowance.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/78-higher-duties-allowance.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/allowances/78-higher-duties-allowance.md"};function r(s,e,h,l,p,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_78-higher-duties-allowance" tabindex="-1">78. Higher Duties Allowance <a class="header-anchor" href="#_78-higher-duties-allowance" aria-label="Permalink to &quot;78. Higher Duties Allowance&quot;">​</a></h1><p><strong>78.1</strong> This clause shall not apply to an Employee over the level of RPN5 if they are not undertaking direct clinical work.</p><p><strong>78.2</strong> An Employee, other than an RPN classified above RPN 5, not undertaking direct clinical work engaged in any one day or shift for more than two hours on duties carrying a higher rate than the classification in which they is ordinarily employed shall be paid for the full day or shift at the minimum rate for that higher classification but if so engaged for two hours or less only the time so worked shall be paid for at that higher rate.</p><p><strong>78.3</strong> Notwithstanding the provisions of sub-clause 78.1 above, the following provisions shall apply to Employees who are appointed to relieve a Unit Manager:</p><p><strong>(a)</strong> Off Duty Shifts</p><p><strong>(i)</strong> Where a work unit involves shift work, Associate Nurse Unit Managers (ANUM) may be appointed to undertake in-charge functions during the off-duty periods of the Unit Manager. The rate of pay assigned to RPN Grade 3 includes payment for the performance of the in-charge function during the off-duty periods of the Unit Manager.</p><p><strong>(ii)</strong> Where an RPN other than an ANUM is required to act in-charge during the off-duty period of an ANUM (which event shall be the exception to the rule), such RPN shall be paid at the minimum rate applicable to the Associate Nurse Unit Manager position which would normally be in- charge on that shift.</p><p><strong>(iii)</strong> Provided that where no ANUM position has been appointed with respect to the relevant shift, the provisions of sub-clause 78.1 above shall apply.</p><p><strong>(b)</strong> Periods of Absence</p><p><strong>(i)</strong> The provisions of sub-clause 78.1 shall apply to all periods of absence of a Unit Manager up to and including five days. For absences in excess of five days, the relieving ANUM shall be paid at the minimum rate for the Unit Manager for the entire period of relief and other Employees who consequently act in a higher position shall be similarly remunerated at the minimum rate of that higher position for the entire period of relief.</p><p><strong>(ii)</strong> An RPN above the level of RPN 6 who is called upon to relieve an RPN in a higher classification for a period in excess of five days, shall be paid at the minimum of that higher classification for the entire period of relief.</p>',11)])])}const g=t(n,[["render",r]]);export{d as __pageData,g as default};
